package com.indianservers.aiexplorer.chemistry.formulas.data

import com.indianservers.aiexplorer.chemistry.formulas.model.*

object BundledChemistryFormulaData {
    const val SCHEMA_VERSION = 1
    private data class Seed(val id: String, val title: String, val topics: List<String>)
    private fun topics(value: String) = value.split(';').map(String::trim)
    private val seeds = listOf(
        Seed("basic-calculations", "Basic Chemical Calculations", topics("Relative Atomic Mass;Relative Molecular Mass;Formula Mass;Mole Concept;Avogadro Constant;Number of Particles;Molar Mass;Percentage Composition;Empirical Formula;Molecular Formula;Percentage Purity;Percentage Yield")),
        Seed("atomic-structure", "Atomic Structure", topics("Atomic Composition;Mass Number;Isotopes;Average Atomic Mass;Photon Energy;Frequency and Wavelength;de Broglie Relation;Uncertainty Principle;Bohr Model;Rydberg Equation")),
        Seed("electronic-structure", "Electronic Structure", topics("Quantum Numbers;Orbitals;Electron Capacity;Electron Configuration;Aufbau Principle;Hund's Rule;Pauli Exclusion Principle;Effective Nuclear Charge;Slater-rule Foundations")),
        Seed("periodic-properties", "Periodic Properties", topics("Atomic Radius;Ionic Radius;Ionisation Energy;Electron Affinity;Electronegativity;Effective Nuclear Charge;Screening;Periodic Trends")),
        Seed("chemical-bonding", "Chemical Bonding", topics("Ionic Bonding;Covalent Bonding;Bond Order;Formal Charge;Resonance;Bond Polarity;Dipole Moment;Lattice Energy;Born-Haber Cycle;VSEPR;Hybridisation;Molecular Orbital Theory")),
