        Seed("gas-laws", "Gas Laws", topics("Boyle's Law;Charles's Law;Gay-Lussac's Law;Avogadro's Law;Combined Gas Law;Ideal Gas Law;Dalton's Law;Graham's Law;van der Waals Equation;Gas Density;Molar Volume")),
        Seed("stoichiometry", "Stoichiometry", topics("Balanced Equations;Mole Ratios;Mass-mass Calculations;Mass-volume Calculations;Volume-volume Calculations;Limiting Reagent;Excess Reagent;Theoretical Yield;Actual Yield;Percentage Yield;Reaction Equivalents")),
        Seed("solutions", "Solutions", topics("Concentration;Molarity;Molality;Normality;Mole Fraction;Mass Percentage;Volume Percentage;Parts per Million;Parts per Billion;Dilution;Solubility")),
        Seed("colligative-properties", "Colligative Properties", topics("Relative Lowering of Vapour Pressure;Boiling-point Elevation;Freezing-point Depression;Osmotic Pressure;van 't Hoff Factor;Molar-mass Determination")),
        Seed("thermochemistry", "Thermochemistry", topics("Heat;Specific Heat;Calorimetry;Enthalpy;Standard Enthalpy;Hess's Law;Bond Enthalpy;Enthalpy of Formation;Enthalpy of Combustion;Enthalpy of Neutralisation")),
        Seed("chemical-thermodynamics", "Chemical Thermodynamics", topics("Internal Energy;First Law;Enthalpy;Entropy;Gibbs Free Energy;Spontaneity;Equilibrium Connection;Standard-state Relationships")),
