        Seed("acids-bases", "Acids, Bases and pH", topics("Arrhenius Model;Brønsted-Lowry Model;Lewis Model;pH;pOH;Ionic Product of Water;Strong Acids;Strong Bases;Weak Acids;Weak Bases;Acid Dissociation Constant;Base Dissociation Constant;Polyprotic Acids;Hydrolysis;Buffers")),
        Seed("ionic-equilibrium", "Ionic Equilibrium", topics("Common-ion Effect;Solubility Product;Precipitation;Selective Precipitation;Salt Hydrolysis;Buffer Systems;Acid-base Indicators")),
        Seed("chemical-kinetics", "Chemical Kinetics", topics("Reaction Rate;Rate Law;Rate Constant;Reaction Order;Integrated Rate Laws;Half-life;Arrhenius Equation;Activation Energy;Collision Theory;Catalysis")),
        Seed("electrochemistry", "Electrochemistry", topics("Oxidation and Reduction;Electrode Potentials;Cell Potential;Nernst Equation;Gibbs Energy;Equilibrium Constant;Electrolysis;Faraday's Laws;Conductance;Conductivity;Molar Conductivity;Batteries")),
        Seed("surface-chemistry", "Surface Chemistry", topics("Adsorption;Freundlich Isotherm;Langmuir Isotherm;Catalysis;Colloids;Coagulation;Surface Area")),
        Seed("spectroscopy", "Spectroscopy", topics("Electromagnetic Radiation;Beer-Lambert Law;UV-visible Spectroscopy;Infrared Spectroscopy;NMR Foundations;Mass Spectrometry;Atomic Spectroscopy;Fluorescence")),
        Seed("analytical-chemistry", "Analytical Chemistry", topics("Gravimetric Analysis;Volumetric Analysis;Titration;Calibration Curves;Standard Addition;Internal Standard;Detection Limit;Error Analysis;Precision;Accuracy;Statistics")),
        Seed("organic-chemistry", "Organic Chemistry", topics("General Formulas;Degree of Unsaturation;Isomer Counting Foundations;Reaction Yield;Optical Rotation;Acid-base Relationships;Reaction Kinetics;Polymer Calculations")),
        Seed("inorganic-chemistry", "Inorganic Chemistry", topics("Oxidation State;Coordination Number;Effective Atomic Number;Crystal Field Splitting;Magnetic Moment;Stability Constants;Complex Formation;Redox Balancing")),
