    val catalogue: ChemistryFormulaCatalogue by lazy {
        val subcategories = seeds.flatMap { seed -> seed.topics.map { title -> ChemistryFormulaSubcategory("${seed.id}-${slug(title)}", seed.id, title, "Quantitative relationships, notation and validity conditions for $title.") } }
        val categories = seeds.map { seed -> ChemistryFormulaCategory(seed.id, seed.title, "An offline formula collection for ${seed.title.lowercase()}.", subcategories.filter { it.categoryId == seed.id }.map { it.id }) }
        ChemistryFormulaCatalogue(SCHEMA_VERSION, categories, subcategories, formulas(subcategories))
    }

    private fun formulas(subcategories: List<ChemistryFormulaSubcategory>): List<ChemistryFormula> {
        fun f(id: String, category: String, subcategory: String, title: String, equation: String, spoken: String, level: ChemistryFormulaLevel, vars: String, example: String, calculator: Boolean = true, derivation: Boolean = true, keywords: String = title): ChemistryFormula {
            val subId = subcategories.first { it.categoryId == category && it.title == subcategory }.id
            val variables = vars.split(';').filter(String::isNotBlank).map { spec -> spec.split('|').let { ChemistryFormulaVariable(it[0],it[1],it[2],it[2],it.getOrNull(3)?.ifBlank{null},it.getOrNull(4)?.ifBlank{null}) } }
            return ChemistryFormula(id,category,subId,title,equation,equation.replace("·","*").replace("²","^2"),spoken,"Use this relationship with balanced chemistry, compatible units, and the stated temperature or standard-state convention.",level,variables,
                listOf("Amounts and units are consistent; temperature is in kelvin when required."),listOf("Approximations and standard-state choices must be checked before use."),emptyList(),
                if(derivation) listOf(ChemistryDerivationStep(equation,"This form follows from the stated chemical definition or model.")) else emptyList(),
                listOf(ChemistryWorkedExample(example,"Convert inputs to compatible units and substitute.","Evaluate with appropriate significant figures and chemical units.","The quantities and units are consistent with the defining relationship.")),
                "Units on both sides are compatible with the stated chemical quantity.",if(calculator) ChemistryCalculatorDefinition(variables.map{it.id}.toSet(),variables.map{it.id}.toSet()) else null,emptyList(),emptyList(),
                (keywords.lowercase().split(Regex("[^a-z0-9]+"))+title.lowercase().split(' ')).filter{it.isNotBlank()}.toSet(),featured=level.rank<=ChemistryFormulaLevel.Class10.rank)
        }
        return listOf(
            f("chem-moles", "basic-calculations", "Mole Concept", "Amount of substance", "n = m / M", "amount in moles equals mass divided by molar mass", ChemistryFormulaLevel.Class9, "amount|n|amount of substance|mol|[N];mass|m|sample mass|g|[M];molarMass|M|molar mass|g/mol|[M N⁻¹]", "Find moles in 18.0 g of water with molar mass 18.0 g/mol.", keywords="moles mole concept molar mass"),
            f("chem-photon-energy", "atomic-structure", "Photon Energy", "Photon energy", "E = hν", "photon energy equals Planck constant multiplied by frequency", ChemistryFormulaLevel.Class11, "energy|E|photon energy|J|[M L² T⁻²];frequency|ν|frequency|Hz|[T⁻¹]", "Find the energy of radiation of known frequency."),
            f("chem-electron-capacity", "electronic-structure", "Electron Capacity", "Maximum shell capacity", "N = 2n²", "maximum shell population equals two times principal quantum number squared", ChemistryFormulaLevel.Class11, "capacity|N|maximum electrons||1;shell|n|principal quantum number||1", "Find the maximum electron capacity of the third shell."),
            f("chem-effective-charge", "periodic-properties", "Effective Nuclear Charge", "Simple effective nuclear charge model", "Zₑff ≈ Z − S", "effective nuclear charge is approximately nuclear charge minus screening constant", ChemistryFormulaLevel.Undergraduate, "effective|Zₑff|effective nuclear charge||1;atomic|Z|atomic number||1;screening|S|screening constant||1", "Estimate effective nuclear charge using a stated screening model.", calculator=false, keywords="periodic effective nuclear charge screening approximate model"),
            f("chem-formal-charge", "chemical-bonding", "Formal Charge", "Formal charge", "FC = V − N − B/2", "formal charge equals valence electrons minus nonbonding electrons minus half bonding electrons", ChemistryFormulaLevel.Class11, "charge|FC|formal charge||1;valence|V|valence electrons||1;nonbonding|N|nonbonding electrons||1;bonding|B|bonding electrons||1", "Calculate formal charge for an atom in a Lewis structure."),
            f("chem-density", "states-matter", "Density", "Density", "ρ = m / V", "density equals mass divided by volume", ChemistryFormulaLevel.Class8, "density|ρ|density|kg/m³|[M L⁻³];mass|m|mass|kg|[M];volume|V|volume|m³|[L³]", "Find density from 2.0 g occupying 1.0 mL."),
            f("chem-ideal-gas", "gas-laws", "Ideal Gas Law", "Ideal gas law", "PV = nRT", "pressure times volume equals amount times gas constant times absolute temperature", ChemistryFormulaLevel.Class11, "pressure|P|pressure|Pa|[M L⁻¹ T⁻²];volume|V|volume|m³|[L³];amount|n|amount|mol|[N];temperature|T|absolute temperature|K|[K]", "Find gas volume from pressure, amount and kelvin temperature.", keywords="ideal gas pv nrt gas law pressure volume"),
            f("chem-mole-ratio", "stoichiometry", "Mole Ratios", "Stoichiometric mole ratio", "nₐ/a = nᵦ/b", "moles of A divided by its coefficient equals moles of B divided by its coefficient", ChemistryFormulaLevel.Class10, "amountA|nₐ|amount of A|mol|[N];coefficientA|a|coefficient of A||1;amountB|nᵦ|amount of B|mol|[N];coefficientB|b|coefficient of B||1", "Use a balanced equation to convert reactant moles to product moles."),
            f("chem-molarity", "solutions", "Molarity", "Molar concentration", "c = n / V", "molar concentration equals amount divided by solution volume", ChemistryFormulaLevel.Class10, "concentration|c|molar concentration|mol/L|[N L⁻³];amount|n|solute amount|mol|[N];volume|V|solution volume|L|[L³]", "Dissolve 0.50 mol to make 2.0 L solution.", keywords="molarity concentration moles volume"),
            f("chem-osmotic-pressure", "colligative-properties", "Osmotic Pressure", "Osmotic pressure", "π = i c R T", "osmotic pressure equals van 't Hoff factor times concentration times gas constant times temperature", ChemistryFormulaLevel.Class12, "pressure|π|osmotic pressure|Pa|[M L⁻¹ T⁻²];factor|i|van 't Hoff factor||1;concentration|c|amount concentration|mol/m³|[N L⁻³];temperature|T|temperature|K|[K]", "Find osmotic pressure of a dilute solution at known temperature."),
            f("chem-calorimetry", "thermochemistry", "Specific Heat", "Heat transfer", "q = mcΔT", "heat equals mass times specific heat capacity times temperature change", ChemistryFormulaLevel.Class10, "heat|q|heat|J|[M L² T⁻²];mass|m|mass|kg|[M];capacity|c|specific heat capacity|J/(kg·K)|[L² T⁻² K⁻¹];temperature|ΔT|temperature change|K|[K]", "Calculate heat for a sample warmed by a known temperature interval."),
            f("chem-gibbs", "chemical-thermodynamics", "Gibbs Free Energy", "Gibbs free-energy change", "ΔG = ΔH − TΔS", "Gibbs energy change equals enthalpy change minus temperature times entropy change", ChemistryFormulaLevel.Class12, "gibbs|ΔG|Gibbs energy change|J/mol|[M L² T⁻² N⁻¹];enthalpy|ΔH|enthalpy change|J/mol|[M L² T⁻² N⁻¹];temperature|T|temperature|K|[K];entropy|ΔS|entropy change|J/(mol·K)|[M L² T⁻² N⁻¹ K⁻¹]", "Evaluate spontaneity from enthalpy and entropy changes at a stated temperature."),
            f("chem-equilibrium-constant", "chemical-equilibrium", "Equilibrium Constant", "Concentration equilibrium constant", "Kc = ∏[products]^ν / ∏[reactants]^ν", "K c equals product activities over reactant activities raised to stoichiometric coefficients", ChemistryFormulaLevel.Class11, "constant|Kc|equilibrium constant||1;coefficient|ν|stoichiometric coefficient||1", "Construct Kc from a balanced homogeneous reaction.", calculator=false, keywords="equilibrium kc reaction quotient products reactants"),
            f("chem-ph", "acids-bases", "pH", "pH", "pH = −log₁₀ a(H⁺)", "p H equals negative base ten logarithm of hydrogen ion activity", ChemistryFormulaLevel.Class10, "ph|pH|pH||1;activity|a(H⁺)|hydrogen ion activity||1", "Find pH for hydrogen-ion activity 1.0 × 10⁻³.", keywords="ph acid hydrogen concentration log"),
            f("chem-ksp", "ionic-equilibrium", "Solubility Product", "Solubility product", "Ksp = ∏ aᵢ^νᵢ", "solubility product equals ion activities raised to stoichiometric powers", ChemistryFormulaLevel.Class12, "constant|Ksp|solubility product||1;activity|aᵢ|ion activity||1;coefficient|νᵢ|stoichiometric coefficient||1", "Write Ksp for a sparingly soluble salt.", calculator=false),
            f("chem-first-order", "chemical-kinetics", "Integrated Rate Laws", "First-order integrated rate law", "ln([A]₀/[A]ₜ) = kt", "natural log of initial concentration over concentration at time t equals rate constant times time", ChemistryFormulaLevel.Class12, "initial|[A]₀|initial concentration|mol/L|[N L⁻³];remaining|[A]ₜ|concentration at time t|mol/L|[N L⁻³];constant|k|first-order rate constant|s⁻¹|[T⁻¹];time|t|time|s|[T]", "Find concentration remaining for a known first-order rate constant."),
            f("chem-nernst", "electrochemistry", "Nernst Equation", "Nernst equation", "E = E° − (RT/nF) ln Q", "cell potential equals standard potential minus R T over electron number and Faraday constant times natural log reaction quotient", ChemistryFormulaLevel.Class12, "potential|E|cell potential|V|[V];standard|E°|standard cell potential|V|[V];temperature|T|temperature|K|[K];electrons|n|electrons transferred||1;quotient|Q|reaction quotient||1", "Calculate a non-standard cell potential from E°, temperature and Q.", keywords="nernst electrochemistry cell potential electrode"),
            f("chem-langmuir", "surface-chemistry", "Langmuir Isotherm", "Langmuir surface coverage", "θ = KP/(1 + KP)", "fractional coverage equals K P divided by one plus K P", ChemistryFormulaLevel.Undergraduate, "coverage|θ|fractional coverage||1;constant|K|adsorption equilibrium constant|Pa⁻¹|;pressure|P|gas pressure|Pa|[M L⁻¹ T⁻²]", "Find surface coverage at a specified pressure.", keywords="adsorption langmuir isotherm surface"),
            f("chem-beer-lambert", "spectroscopy", "Beer-Lambert Law", "Beer–Lambert law", "A = εbc", "absorbance equals molar absorptivity times path length times concentration", ChemistryFormulaLevel.Class12, "absorbance|A|absorbance|AU|1;absorptivity|ε|molar absorptivity|L/(mol·cm)|;path|b|path length|cm|[L];concentration|c|concentration|mol/L|[N L⁻³]", "Find concentration from absorbance, path length and absorptivity.", keywords="beer lambert absorbance spectroscopy concentration"),
            f("chem-standard-deviation", "analytical-chemistry", "Statistics", "Sample standard deviation", "s = √[Σ(xᵢ − x̄)²/(n − 1)]", "sample standard deviation is square root of squared deviations divided by n minus one", ChemistryFormulaLevel.Undergraduate, "deviation|s|sample standard deviation||;observation|xᵢ|observation||;mean|x̄|sample mean||;count|n|sample count||1", "Calculate precision from replicate analytical measurements.", calculator=false),
            f("chem-unsaturation", "organic-chemistry", "Degree of Unsaturation", "Degree of unsaturation", "DBE = C − H/2 + N/2 + 1", "double bond equivalents equal carbon count minus half hydrogen count plus half nitrogen count plus one", ChemistryFormulaLevel.Class12, "dbe|DBE|double bond equivalents||1;carbon|C|carbon atoms||1;hydrogen|H|hydrogen plus halogen atoms||1;nitrogen|N|nitrogen atoms||1", "Find DBE for a neutral closed-shell organic molecular formula."),
            f("chem-magnetic-moment", "inorganic-chemistry", "Magnetic Moment", "Spin-only magnetic moment", "μ = √[n(n + 2)] μB", "magnetic moment equals square root of n times n plus two Bohr magnetons", ChemistryFormulaLevel.Undergraduate, "moment|μ|magnetic moment|μB|;unpaired|n|unpaired electrons||1", "Estimate spin-only moment from the number of unpaired electrons."),
            f("chem-radioactive-decay", "nuclear-chemistry", "Radioactive Decay", "Radioactive decay law", "N = N₀e^(−λt)", "remaining nuclei equal initial nuclei times exponential negative decay constant times time", ChemistryFormulaLevel.Class12, "remaining|N|remaining nuclei||1;initial|N₀|initial nuclei||1;constant|λ|decay constant|s⁻¹|[T⁻¹];time|t|elapsed time|s|[T]", "Find the remaining isotope fraction after a stated time."),
            f("chem-unit-cell-density", "solid-state", "Density", "Unit-cell density", "ρ = ZM/(Nₐa³)", "crystal density equals formula units times molar mass divided by Avogadro constant times cell edge cubed", ChemistryFormulaLevel.Class12, "density|ρ|crystal density|kg/m³|[M L⁻³];units|Z|formula units per cell||1;molarMass|M|molar mass|kg/mol|[M N⁻¹];edge|a|cubic cell edge|m|[L]", "Find cubic-crystal density from unit-cell data."),
            f("chem-michaelis-menten", "biochemistry-calculations", "Enzyme Kinetics", "Michaelis–Menten equation", "v = Vₘₐₓ[S]/(Kₘ + [S])", "rate equals maximum rate times substrate concentration divided by K m plus substrate concentration", ChemistryFormulaLevel.Undergraduate, "rate|v|reaction rate|mol/(L·s)|[N L⁻³ T⁻¹];maximum|Vₘₐₓ|maximum rate|mol/(L·s)|[N L⁻³ T⁻¹];substrate|[S]|substrate concentration|mol/L|[N L⁻³];constant|Kₘ|Michaelis constant|mol/L|[N L⁻³]", "Find enzyme rate at a specified substrate concentration."),
            f("chem-chemical-potential", "advanced-physical", "Chemical Potential", "Chemical potential", "μ = μ° + RT ln a", "chemical potential equals standard chemical potential plus R T times natural log activity", ChemistryFormulaLevel.Undergraduate, "potential|μ|chemical potential|J/mol|[M L² T⁻² N⁻¹];standard|μ°|standard chemical potential|J/mol|[M L² T⁻² N⁻¹];temperature|T|temperature|K|[K];activity|a|activity||1", "Find chemical potential relative to a defined standard state.", keywords="advanced physical chemistry activity chemical potential"),
        )
    }
    private fun slug(value: String)=value.lowercase().replace(Regex("[^a-z0-9]+"),"-").trim('-')
}

